module top_module(dataIn, dataOut);parameter PC_BIT_WIDTH = 32;
	input  [PC_BIT_WIDTH - 1: 0] dataIn;
	output reg [PC_BIT_WIDTH - 1: 0] dataOut;

	always @(dataIn) begin
		dataOut <= dataIn + 4;
	end
  always @(*) begin
    if (1'b0) begin
      dataOut <= dataIn - 4;
    end
  end

endmodule
